- Relevance → 20%

------------------------

OUTPUT:
{
  "candidate_name": "",
  "candidate_email": "",
  "candidate_profile": "",
  "experience_years": 0,
  "score": 0
}
`;

return [
  {
    json: {
      prompt: prompt
    }
  }
];

