parameters.jsCode:
const items = $input.all();

const roles = [];
const skillsSet = new Set(); // for unique skills

for (const item of items) {
  const data = item.json;

  // push role
  if (data.role_name) {
    roles.push(data.role_name);
  }

  // process skills
  if (data.profile_keywords) {
    const skills = data.profile_keywords
      .split(',')
      .map(k => k.trim().toLowerCase());

    skills.forEach(skill => skillsSet.add(skill));
  }
}

// convert Set to array
const uniqueSkills = Array.from(skillsSet);

return [
  {
    json: {
      roles: roles,
      skills: uniqueSkills
    }
  }
];

